-- =============================================================================
-- TeachNexis CIG Seed — Sprint 4c: JSS Curriculum (JSS1–JSS3)
-- ~280 topics | 8 subjects | JSS1–JSS3 | 4 topics per (subject, class, term)
-- Run AFTER seed-cig.sql. Safe to re-run (deletes JSS nodes first).
-- =============================================================================

-- ─── 1. Clear JSS global nodes ────────────────────────────────────────────────
DELETE FROM curriculum_nodes
WHERE "schoolId" IS NULL
  AND "classLevel" IN ('JS1'::"ClassLevel",'JS2'::"ClassLevel",'JS3'::"ClassLevel");

-- Also clear JSS-only subject nodes so the seed is idempotent
DELETE FROM curriculum_nodes
WHERE "schoolId" IS NULL
  AND "type" = 'SUBJECT'::"NodeType"
  AND "label" IN ('Basic Science','Social Studies','Agricultural Science','Business Studies','Civic Education','Home Economics');

