-- ─── 10. PART_OF edges (auto — topic.subject → subject node) ─────────────────
INSERT INTO curriculum_edges ("id","sourceId","targetId","relationship","weight","createdAt")
SELECT gen_random_uuid()::TEXT, t."id", s."id", 'PART_OF'::"EdgeRelation", 1.0, now()
FROM curriculum_nodes t
JOIN curriculum_nodes s ON s."label" = t."subject" AND s."type" = 'SUBJECT'::"NodeType" AND s."schoolId" IS NULL
WHERE t."type" = 'TOPIC'::"NodeType"
  AND t."schoolId" IS NULL
  AND t."classLevel" IN ('JS1'::"ClassLevel",'JS2'::"ClassLevel",'JS3'::"ClassLevel")
  AND NOT EXISTS (
    SELECT 1 FROM curriculum_edges e WHERE e."sourceId" = t."id" AND e."relationship" = 'PART_OF'::"EdgeRelation"
  );

-- ─── 11. TEACHES_BEFORE edges (auto — week ordering within bucket) ─────────────
INSERT INTO curriculum_edges ("id","sourceId","targetId","relationship","weight","createdAt")
WITH ordered AS (
  SELECT "id", LAG("id") OVER (PARTITION BY "subject","classLevel","term" ORDER BY "week") AS prev_id
  FROM curriculum_nodes
  WHERE "type" = 'TOPIC'::"NodeType"
    AND "schoolId" IS NULL
    AND "classLevel" IN ('JS1'::"ClassLevel",'JS2'::"ClassLevel",'JS3'::"ClassLevel")
    AND "week" IS NOT NULL
)
SELECT gen_random_uuid()::TEXT, prev_id, "id", 'TEACHES_BEFORE'::"EdgeRelation", 1.0, now()
FROM ordered WHERE prev_id IS NOT NULL;

-- ─── 12. JSS3 → SS1 bridge edges (TEACHES_BEFORE: last JSS3 topic → first SS1 topic) ──
INSERT INTO curriculum_edges ("id","sourceId","targetId","relationship","weight","createdAt")
SELECT gen_random_uuid()::TEXT, jss."id", ss."id", 'TEACHES_BEFORE'::"EdgeRelation", 1.0, now()
FROM (VALUES
  ('Number Bases',             'Number Systems & Indices'),
  ('Revision: Physical Science (Basic)', 'Introduction to Chemistry'),
  ('Revision: Life Science Concepts',   'Cell Structure & Organisation'),
  ('Oral English: BECE Preparation',    'Summary Writing'),
  ('Globalisation: Introduction',       'Introduction to Economics'),
  ('Conflict Resolution',               'Basic Concepts in Government'),
  ('Revision: Literature Concepts for BECE', 'Introduction to Poetry')
) AS bridges(jss_label, ss_label)
JOIN curriculum_nodes jss ON jss."label" = bridges.jss_label AND jss."schoolId" IS NULL
JOIN curriculum_nodes ss  ON ss."label"  = bridges.ss_label  AND ss."schoolId" IS NULL;

