  -- Health & Social Issues: Basic Science ↔ Civic Education ↔ Home Economics
  ('Drug & Substance Abuse (Basic Science)',      'Drug & Substance Abuse (Civic)'),
  ('Adolescent Health & Puberty',                 'Family Life Education'),
  ('First Aid: Introduction',                     'Personal & Environmental Hygiene'),
  ('Microorganisms & Disease',                    'Environmental Pollution & Conservation'),
  -- Government & Society: Social Studies ↔ Civic Education
  ('Types of Government',                         'Democratic Governance'),
  ('Citizens'' Rights & Responsibilities',        'Fundamental Human Rights'),
  ('Corruption & Anti-Corruption',                'Anti-Corruption'),
  ('Security Challenges in Nigeria',              'Security Challenges'),
  ('Nigerian Government Structure',               'Three Arms of Government'),
  ('Human Rights & Democracy Review',             'Citizenship & Human Rights Revision'),
  -- Agriculture ↔ Basic Science
  ('Crop Diseases & Pests',                       'Microorganisms & Disease'),
  ('Plant Genetics & Crop Improvement',           'Genetics & Heredity (Basic)'),
  ('Soil: Types & Properties',                    'Air Water & Soil'),
  -- Business ↔ Social Studies
  ('Trade & Commerce in Nigeria',                 'Trade & Commerce in Business'),
  ('Agricultural Resources of Nigeria',           'Farm Records & Simple Accounts'),
